import type { Quiz } from "../quiz-types.js";

export const week4Quizzes: Quiz[] = [
  {
    id: "day11", day: "Day 11", title: "Forecasting (including Services)", week: "Week 4",
    questions: [
      { id: 1, type: "mc", lo: "LO1", text: "Every AE is responsible for forecasting their business. How often is the current quarter forecast submitted, and when is the next quarter forecast reviewed?", options: ["Both current and next quarter forecasts are submitted weekly", "Current quarter forecast is submitted weekly; next quarter forecast is reviewed the first week of each month", "Current quarter forecast is submitted bi-weekly; next quarter forecast is submitted at the start of each quarter", "Forecasts are submitted on demand when your FLM requests them"], correct: 1, explanation: "Per the forecasting deck: AEs submit a current quarter forecast every week, broken down by month. Next quarter forecast is reviewed the first week of each month. Every AE has a weekly meeting with management to discuss their Commit (forecast) and which deals are included. This cadence connects to the weekly forecasting process: AEs update opportunities and submit on Monday/Tuesday; FLMs review and submit Wednesday; VPs and CRO review Thursday; President review happens Friday.", resource: { label: "Forecasting Slides — Forecast Schedule (Weekly Current Quarter, Monthly Next Quarter)", url: "https://docs.google.com/presentation/d/19-B_1a-oBmuMoI_4lc1L5W1oiZZN6pXALYMZObBc9L8/edit" } },
      { id: 2, type: "mc", lo: "LO1", text: "What are the four forecast categories for new business, from most conservative to most aggressive?", options: ["Closed, Commit, Strong Upside, Upside", "Worst Case, Commit, Best Case, Stretch", "Closed Won, Commit, Upside, Pipeline", "Conservative, Realistic, Optimistic, Stretch"], correct: 0, explanation: "The four new business forecast categories are: Closed Won (already booked), Commit (deals you're committing will close this period — your 'most likely' number), Strong Upside (deals with good probability but not fully committed), and Upside (possible but less certain). Your Worst Case forecast = Closed Won + Commit + some Strong Upside. Your full Commit = Closed Won + Commit + some Strong Upside + some Upside. Knowing these definitions is essential for having credible forecast conversations with your FLM.", resource: { label: "Forecasting Slides — New Business Forecasting: Worst Case, Commit, Goal, Best Case", url: "https://docs.google.com/presentation/d/19-B_1a-oBmuMoI_4lc1L5W1oiZZN6pXALYMZObBc9L8/edit" } },
      { id: 3, type: "mc", lo: "LO2", text: "Your FLM asks for your Worst Case forecast number. You have $50K Closed Won, $80K in Commit, $40K Strong Upside, and $30K Upside. What should your Worst Case be?", options: ["$50K — Worst Case is only Closed Won", "$130K — Worst Case is Closed Won + Commit", "Between $150K–$170K — Worst Case is Closed Won + Commit + some Strong Upside", "$200K — Worst Case is everything you could possibly close"], correct: 2, explanation: "Worst Case = Closed Won + Commit + some Strong Upside. In this example: $50K (CW) + $80K (Commit) = $130K as the base. Adding 'some' Strong Upside from the $40K pool puts Worst Case in the $150K–$170K range depending on deal specifics. Worst Case is defined as the 'realistic worst case or minimum amount you will close by end of the period, irrespective of unforeseen headwinds.' It's not just CW — and it's not everything including pure Upside. The precision of this number is what makes you credible with leadership.", resource: { label: "Forecasting Slides — New Business Forecasting: Forecast Category Definitions", url: "https://docs.google.com/presentation/d/19-B_1a-oBmuMoI_4lc1L5W1oiZZN6pXALYMZObBc9L8/edit" } },
      { id: 4, type: "mc", lo: "LO3", text: "An AE moves a deal from Upside to Commit in Salesforce on Monday but doesn't update the opportunity's close date, stage, or last activity. Their FLM reviews it Wednesday. What problem does this create?", options: ["No problem — changing the forecast category is sufficient for the FLM to review accurately", "The FLM will move the deal back to Upside — forecast categories must match deal stage", "The forecast category change creates a mismatch between what the AE is claiming (Commit) and the evidence in the opportunity record (stale close date, wrong stage, no recent activity). A forecast without evidence in SFDC is a forecast the FLM can't trust — and one leadership can't review at the VP/CRO level. SFDC and Outreach must be reviewed for completeness before forecast submission.", "Nothing — the FLM will add the missing information after the forecast review call"], correct: 2, explanation: "Forecasting at Amplitude requires SFDC evidence to support the forecast claim. Per the forecasting deck, 'SF/Outreach reviewed for completeness → Submit Forecasts' is a pre-submission requirement at every level of the cadence. A deal in Commit must have: updated close date, correct stage, recent activity logged, and a clear MEDDPICC picture. Without it, the FLM has no basis to pass the forecast up the chain — and when leadership reviews larger deals on Friday, discrepancies between claimed Commit and SFDC evidence damage the AE's credibility.", resource: { label: "Forecasting Slides — Weekly Forecasting Process (SF/Outreach Reviewed for Completeness)", url: "https://docs.google.com/presentation/d/19-B_1a-oBmuMoI_4lc1L5W1oiZZN6pXALYMZObBc9L8/edit" } },
      { id: 5, type: "tf", lo: "LO1", text: "True or False: Services (PS and PSP) are included in the same forecast as New Business and Renewals.", options: ["True", "False"], correct: 1, explanation: "There are three distinct forecast types: New Business, Renewals, and Services. Services forecasting exists because PS and PSP revenue is recognized differently, requires separate capacity planning for PS staffing, and is tracked independently for business visibility. AEs are responsible for all three — forecasting a deal without its associated Services component creates blind spots for the PS team. When attaching implementation to a deal, ensure the Services component is forecasted alongside the subscription ARR.", resource: { label: "Forecasting Slides — Types of Forecasts (New Business, Renewals, Services)", url: "https://docs.google.com/presentation/d/19-B_1a-oBmuMoI_4lc1L5W1oiZZN6pXALYMZObBc9L8/edit" } },
      { id: 6, type: "mc", lo: "LO3", text: "You're in a Wednesday meeting with your FLM for your weekly forecast review. They push back on a deal you have in Commit: 'I don't see the Economic Buyer engaged, no MAP in the SFDC notes, and the close date hasn't changed in 3 weeks.' Applying the CEM and forecasting standards, is your FLM right to push back?", options: ["No — the AE's judgment on deal stage and forecast category is the primary signal", "Yes. At S2+ (which a Commit deal should be), MEDDPICC must be populated — including Economic Buyer confirmed. A MAP must be in place for deals at S3+. A close date that hasn't moved in 3 weeks with no activity signals a stalled deal, not a Commit. The FLM is doing exactly what the forecasting process requires: using SFDC evidence to pressure-test claims.", "No — a deal can be in Commit without EB engagement as long as the Champion is actively working it", "Yes, but only for deals over $100K — smaller deals can stay in Commit with less SFDC evidence"], correct: 1, explanation: "This is what a good FLM review looks like. Per the CEM, Economic Buyer engagement is required at S2 exit. A MAP is required at S3+ for deals over $100K. A stale close date with no activity is a red flag, not a forecasting artifact. Moving a deal to Commit without SFDC evidence to support it is the most common forecasting mistake AEs make — it inflates the number, destroys credibility with leadership, and masks deal risk that should be addressed. The FLM's job is to ensure the forecast reflects reality, not aspiration.", resource: { label: "Customer Engagement Model — S2 Qualification Exit Criteria (MEDDPICC + EB Confirmed)", url: "https://docs.google.com/document/d/1VxMWNbIWWEtJwuhNibKHUCsbOsCQqVFcin8vrZkeKZw/edit" } },
      { id: 7, type: "mc", lo: "LO1", text: "The weekly forecasting cadence runs Monday through Friday with activities at each level. On what day does the AE's primary responsibility occur?", options: ["Friday — AEs submit their forecast at the end of the week", "Wednesday — AEs update opportunities and submit forecasts before the FLM review call", "Monday and Tuesday — AEs update opportunities and submit forecasts before the Wednesday FLM call", "Thursday — AEs update before the VP call"], correct: 2, explanation: "Per the weekly forecasting process: AEs update opportunities and submit forecasts on Monday and Tuesday. This feeds the FLM review (which includes AEs and CSMs) on Wednesday. The FLM then submits to the VP, who reviews Thursday. The VP submits to the CRO, who reviews Friday. The President Forecast Call is also Friday. The entire chain depends on AEs updating SFDC and submitting forecasts on Monday/Tuesday — anything later breaks the cadence and leaves FLMs working with stale data.", resource: { label: "Forecasting Slides — Weekly Forecasting Process (AEs Update Mon/Tue)", url: "https://docs.google.com/presentation/d/19-B_1a-oBmuMoI_4lc1L5W1oiZZN6pXALYMZObBc9L8/edit" } },
      { id: 8, type: "fill", lo: "LO1", text: "The Amplitude tool that delivers AI-generated deal updates, call summaries, and opportunity field recommendations directly into Slack — reducing manual SFDC updates for AEs — is called ________.", correct: ["Momentum", "momentum"], placeholder: "tool name...", explanation: "Momentum is the conversation intelligence platform that converts call insights into deal updates, delivering them into Slack DMs, account channels, and SFDC opportunity records. In the context of forecasting, Momentum reduces the manual burden of keeping SFDC current — which is the prerequisite for accurate forecasting. If SFDC is stale, the forecast is stale. Momentum's Phase 1 covers AEs and SDRs; Phase 2 extends to post-sales and renewals.", resource: { label: "Momentum (for Slack) Deck — Executive Summary (What It Is)", url: "https://docs.google.com/presentation/d/129YPTu9OKQYZM6fFIMxlsJOqalqUWcwlLvLnC4lOvXI/edit" } },
      { id: 9, type: "mc", lo: "LO3", text: "An AE has a deal at S4 (Proof of Value) with $200K subscription ARR and $40K in PSP Advanced attached. When forecasting this deal, how should the Services component be handled?", options: ["Include PSP in the subscription ARR number — it's part of the deal total", "Ignore PSP in forecasting — Services are tracked separately by the PS team", "Forecast the Services ($40K PSP + implementation) separately in the Services forecast category, and include the $200K subscription ARR in the New Business forecast. Both must be submitted — AEs are responsible for forecasting all three types.", "Forecast only the ARR; Services are tracked by Finance at close"], correct: 2, explanation: "Services must be forecasted in the Services category — separately from subscription ARR in the New Business category. AEs are responsible for all three forecast types: New Business, Renewals, and Services. Forecasting $200K in New Business without the associated Services component creates a blind spot for PS capacity planning and Financial forecasting. The PS team uses Services forecasts to staff engagements — a Services number that appears at close without prior forecasting creates implementation delays that hurt TTF and adoption.", resource: { label: "Forecasting Slides — Services Forecasting (Must Be Forecast Separately)", url: "https://docs.google.com/presentation/d/19-B_1a-oBmuMoI_4lc1L5W1oiZZN6pXALYMZObBc9L8/edit" } },
      { id: 10, type: "mc", lo: "LO2", text: "Why does Amplitude's leadership invest heavily in the forecasting cadence — weekly calls up through the President level? What are the stated business reasons?", options: ["To monitor individual AE performance and identify underperformers early", "To satisfy investor reporting requirements for a public company", "Four reasons: headcount planning (understanding future revenue to determine hiring needs for SEs, CS, PS), risk mitigation (earlier visibility into revenue risk), business predictability (communicating performance to leadership, board, and investors), and creating a dedicated forum for deal discussion, coaching, and unblocking.", "To ensure accurate commission calculations at the end of each quarter"], correct: 2, explanation: "Per the forecasting deck, the four business reasons for forecasting are: Headcount Planning (expected revenue drives decisions on SE, CS, and PS hiring), Risk Mitigation (greater revenue outlook enables earlier identification of business risks), Business Predictability (investment decisions and communications to leadership/board/investors), and Forum for Deal Discussion (dedicated time for deal status, risks, and coaching). Understanding why forecasting matters — not just how to do it — helps AEs take it seriously as a business contribution, not just a compliance activity.", resource: { label: "Forecasting Slides — Why Do We Forecast? (4 Business Reasons)", url: "https://docs.google.com/presentation/d/19-B_1a-oBmuMoI_4lc1L5W1oiZZN6pXALYMZObBc9L8/edit" } },
    ],
  },
  {
    id: "day12", day: "Day 12", title: "Customer Stories", week: "Week 4",
    questions: [
      { id: 1, type: "mc", lo: "LO1", text: "Where do you go to find curated, approved customer stories organized by industry and use case?", options: ["Google Drive — search for 'customer stories' to find the most recent decks", "Highspot — the Customer Stories hub is the authoritative library for approved, current customer stories organized by industry, use case, and value driver", "Amplitude's public website — all customer case studies are publicly available and always current", "Glean — search for customer name + 'case study' to find the most relevant story"], correct: 1, explanation: "Highspot is the authoritative source for customer stories at Amplitude. It's organized by industry, use case, and value driver — so you can quickly find a story that resonates with a specific prospect's context. Using an outdated Google Drive version or a website link that hasn't been approved for external use creates risk. When in doubt, go to Highspot.", resource: { label: "Customer Stories Highspot Hub", url: "https://amplitude.highspot.com/spots/5f12a41df2c4af64a3d5ff68" } },
      { id: 2, type: "mc", lo: "LO2", text: "An AE drops a generic Amplitude customer case study PDF into an email before a discovery call with a VP of Product at a healthcare tech company. What's wrong with this approach?", options: ["Nothing — customer stories build credibility and should be shared early in the sales cycle", "Customer stories should never be shared before discovery — they reveal Amplitude's positioning prematurely", "A generic story doesn't apply Challenger Tailor. The story must resonate with this specific persona (VP of Product) in this specific industry (healthcare tech) around a pain they've actually described. Sending a retail e-commerce story to a healthcare VP of Product is noise, not signal — and it signals you haven't prepared. Use Highspot to find industry-specific, persona-relevant stories.", "PDFs aren't tracked — use Highspot share links so you can see if they opened it"], correct: 2, explanation: "Customer stories are most powerful when they're Tailored — the Challenger T in Teach-Tailor-Take Control. A generic story signals you haven't done your homework. The right story is industry-matched (healthcare), persona-matched (VP of Product's pain: roadmap validation, feature impact visibility), and use-case-matched to what the prospect has described as their challenge. Highspot's industry and use case filters exist precisely for this. Tracking views is a secondary benefit — the primary value is relevance.", resource: { label: "ICP: Personas & Industries Deck — How to Use Industry Content (Tailor to Persona)", url: "https://docs.google.com/presentation/d/1i6jAipawDy9ER5Bls-FFdXdr4hQA41XKw-wYqK5RttE/edit" } },
      { id: 3, type: "mc", lo: "LO3", text: "You're in an S3 Business & Technical Evaluation with a B2B SaaS prospect. Their champion is enthusiastic but hasn't been able to get their VP of Engineering (the Economic Buyer) engaged. Which use of a customer story best serves a Challenger objective here?", options: ["Send the VP of Engineering a direct email with 3 customer case studies — volume creates credibility", "Use the story to enable your champion: find a story featuring an outcome that would resonate with a VP of Engineering (shipped features faster, trusted data, reduced instrumentation overhead) and coach your champion to share it in their internal sell-through. The story does the Teach for you inside the buying org.", "Save the customer story for the proposal stage — it's more impactful at S5 when the buyer is closer to decision", "Ask your champion to forward the generic product overview PDF to the VP of Engineering — the product overview covers more ground than a single story"], correct: 1, explanation: "This is champion coaching through customer stories — a core Challenger application. Your champion can't always articulate Amplitude's value in Engineering language. A story featuring a VP of Engineering at a similar B2B SaaS company who said 'we can now ship the right features faster and trust our data' gives your champion a credible, peer-level narrative to take into their internal sell-through. You're equipping them to Teach the EB on your behalf. That's more effective than you emailing the EB directly — and it's exactly what the CEM S3 'Champion coaching sessions' activity is designed for.", resource: { label: "Customer Engagement Model — S3 Business & Technical Evaluation: Champion Coaching Sessions", url: "https://docs.google.com/document/d/1VxMWNbIWWEtJwuhNibKHUCsbOsCQqVFcin8vrZkeKZw/edit" } },
      { id: 4, type: "mc", lo: "LO1", text: "Amplitude's three core value drivers that customer stories and use cases are organized around are:", options: ["Analytics, Experimentation, and Activation", "Acquisition, Retention, and Monetization", "Product, Marketing, and Data personas", "Grow, Optimize, and Scale"], correct: 1, explanation: "Amplitude's three core value drivers are Acquisition (getting users), Retention (keeping users), and Monetization (growing revenue from users). Industry-specific use case cheat sheets, customer stories, and value maps are all organized around these three drivers. When you pick a customer story, you're matching the value driver the prospect cares most about — a company struggling with retention churn needs a retention story, not an acquisition story.", resource: { label: "ICP: Personas & Industries Deck — Tying Industry Use Cases to Value (Acquisition/Retention/Monetization)", url: "https://docs.google.com/presentation/d/1i6jAipawDy9ER5Bls-FFdXdr4hQA41XKw-wYqK5RttE/edit" } },
      { id: 5, type: "tf", lo: "LO2", text: "True or False: You should lead with a customer story at the very beginning of an S1 Discovery call to establish Amplitude's credibility before asking any questions.", options: ["True", "False"], correct: 1, explanation: "Customer stories are tools for the Tailor phase of Challenger — not the opening move. Opening with a story before you know what the prospect cares about produces a generic pitch. The right sequence: Teach (open with a commercial insight that challenges their assumption), probe to understand their specific pain, then Tailor the story to exactly what they've told you they're struggling with. A story that lands perfectly in context is exponentially more powerful than a story that opens cold.", resource: { label: "ICP: Personas & Industries Deck — How to Use Industry Content for Prospecting", url: "https://docs.google.com/presentation/d/1i6jAipawDy9ER5Bls-FFdXdr4hQA41XKw-wYqK5RttE/edit" } },
      { id: 6, type: "mc", lo: "LO3", text: "A prospect says: 'We're not sure Amplitude can handle our scale — we have 500M monthly events.' What's the ideal response that uses a customer story?", options: ["Tell them that Amplitude handles billions of events per month and share the technical architecture documentation", "Share a specific customer story from a similar-scale company in their industry — 'We work with [peer company] who processes [comparable scale] events per month. Here's what their Head of Data said about Amplitude's reliability at that scale.' Then offer to connect them with the customer directly if useful.", "Assure them that scale isn't an issue and offer a POV so they can verify for themselves", "Ask them to clarify their exact use case before responding — the scale question depends heavily on event types and complexity"], correct: 1, explanation: "Scale objections are handled best with social proof from a peer company at comparable scale. The most powerful version of a customer story in this context: specific company (well-known enough to resonate), specific scale (comparable to the prospect's), specific outcome quote from a technical stakeholder. If you can arrange a customer reference call, even better — peer-to-peer validation of scale credibility outperforms any Amplitude claim. Know your reference-ready customers in Highspot and your network well enough to deploy this quickly.", resource: { label: "Customer Stories Highspot Hub", url: "https://amplitude.highspot.com/spots/5f12a41df2c4af64a3d5ff68" } },
      { id: 7, type: "mc", lo: "LO1", text: "PODcast recordings are referenced as a resource for Day 12 Customer Stories. What is the primary purpose of these recordings for a new AE?", options: ["They're product demo recordings that show how Amplitude works in real customer environments", "They're recordings of Amplitude Pod teams (AE + CSM + SE) sharing real deal stories — win/loss lessons, customer moments, and field insights that help new AEs understand how the team operates and what good looks like", "They're customer testimonial videos for external use in prospect conversations", "They're internal all-hands recordings where senior leadership discusses company strategy"], correct: 1, explanation: "PODcast recordings feature Amplitude Pod teams sharing real deal stories — wins, losses, key moments, lessons learned. For new AEs, these recordings are a shortcut to institutional knowledge: how deals actually unfold, what customers really say, how the team navigates challenges together. They complement the formal curriculum with real-world texture that no slide deck can fully capture. Listening to a PODcast before a competitive deal or a renewal conversation gives you field-tested patterns, not just frameworks.", resource: { label: "Customer Stories Highspot Hub — PODcast Recordings", url: "https://amplitude.highspot.com/" } },
      { id: 8, type: "fill", lo: "LO1", text: "Amplitude's customer stories are organized in Highspot around three value drivers: Acquisition, Monetization, and ________.", correct: ["Retention", "retention"], placeholder: "third value driver...", explanation: "The three value drivers are Acquisition, Retention, and Monetization. Retention is often the most powerful value driver for Amplitude because it directly connects to the core product analytics use case: understanding why users drop off, what features drive long-term engagement, and how to build products that keep users coming back. When prospecting or preparing for discovery, know which value driver is most relevant to the prospect's current business priority — it determines which stories and use cases to lead with.", resource: { label: "ICP: Personas & Industries Deck — Tying Industry Use Cases to Value Drivers", url: "https://docs.google.com/presentation/d/1i6jAipawDy9ER5Bls-FFdXdr4hQA41XKw-wYqK5RttE/edit" } },
      { id: 9, type: "mc", lo: "LO3", text: "A prospect has given positive buying signals but their Legal team has flagged concerns about data privacy and GDPR compliance. Which type of customer story would be most effective in this situation?", options: ["A product analytics success story from a high-growth B2B SaaS company showing fast time-to-insight", "A customer story from a company in a heavily regulated industry (healthcare or financial services) that specifically addresses how they navigated data privacy, GDPR compliance, and governance with Amplitude", "Any customer story — the buying signal matters more than the story type at this late stage", "Skip the customer story and go straight to sharing Amplitude's SOC 2 certification and security documentation"], correct: 1, explanation: "Legal and compliance objections require peer validation from companies in similarly regulated environments. A customer story from financial services (which must comply with strict data regulations) or healthcare (HIPAA considerations) that specifically speaks to governance, data privacy, and compliance builds credibility in exactly the domain where the objection lives. This is Challenger Tailor applied to legal risk: you're not defending Amplitude's security posture — you're showing that companies with higher compliance requirements have navigated this successfully.", resource: { label: "Customer Stories Highspot Hub — Financial Services & Healthcare Stories", url: "https://amplitude.highspot.com/spots/5f12a41df2c4af64a3d5ff68" } },
      { id: 10, type: "mc", lo: "LO2", text: "You've found a perfect customer story in Highspot for your prospect — it's from a peer company, same industry, same use case, and features a quote from a VP of Product. How do you deploy it most effectively in the deal?", options: ["Send it immediately as a follow-up email — speed is important to maintain momentum", "Reference it verbally in your next call before sending — 'I came across a story from [Company] that reminded me of what you described. Their VP of Product said something that I thought would resonate with you...' Then send the Highspot link so it's tracked. Use it to deepen the pain or validate the value, not as a closing tool.", "Save it for the proposal stage — customer stories are most effective when the customer is actively making a decision", "Forward it to your champion and ask them to share it with stakeholders — your champion is better positioned to deliver it than you are"], correct: 1, explanation: "Deploying a customer story effectively requires context. Referencing it verbally first — framing it around what the prospect has told you — signals you've been listening and makes the story relevant rather than generic. The Highspot share link enables tracking, so you can see if they opened it and forwarded it to other stakeholders (a signal of internal interest). Using the story to deepen pain ('their VP of Product had the same problem you described — here's what it cost them') is more powerful than using it as a closing proof point. Timing, relevance, and delivery method all matter.", resource: { label: "Customer Stories Highspot Hub — Deploying Stories Effectively", url: "https://amplitude.highspot.com/spots/5f12a41df2c4af64a3d5ff68" } },
    ],
  },
  {
    id: "day13", day: "Day 13", title: "Contract Lifecycle Management", week: "Week 4",
    questions: [
      { id: 1, type: "mc", lo: "LO1", text: "What is the CLM system used at Amplitude for contract management?", options: ["DocuSign CLM", "Ironclad", "Salesforce Contracts", "Conga Composer"], correct: 1, explanation: "Ironclad is Amplitude's contract lifecycle management (CLM) system. It manages the end-to-end contract process from creation through archiving. For questions on process, post in #help-legal on Slack. For technical issues in Salesforce related to contracts, submit a ticket to business systems. The CLM Confluence page has step-by-step guides for everything related to customer agreements.", resource: { label: "CLM Slides — CLM: Ironclad", url: "https://docs.google.com/presentation/d/1qlfiR7FE_tkMei8SNNktEAxv0YLausl_gBXxrEvTm54/edit" } },
      { id: 2, type: "match", lo: "LO1", text: "Match each agreement type to its purpose.", pairs: [{ term: "MSA (Master/Main Service Agreement)", match: "Governs the Amplitude Services for customers who have purchased a paid (at least $50K) subscription" }, { term: "NDA (Non-Disclosure Agreement)", match: "Protects Amplitude's confidential and proprietary information during pre-sales" }, { term: "DPA (Data Processing Addendum)", match: "Governs the processing of personal data in connection with a customer's use of Amplitude Services" }, { term: "BAA (Business Associate Addendum)", match: "Permits a customer to process certain personal health information (PHI) through Amplitude Services — required for healthcare customers" }], correct: 0, explanation: "Each agreement type has a specific purpose and timing in the contract lifecycle. NDAs appear in Pre-Sales. Order Forms and MSAs are central to Sales Negotiation. DPAs and BAAs are addenda that address specific data processing and compliance requirements. Knowing which agreement applies when prevents delays at the contract stage — especially for regulated industries (healthcare requiring BAA, EU customers requiring DPA with specific GDPR terms).", resource: { label: "CLM Slides — Most Common Agreement Types", url: "https://docs.google.com/presentation/d/1qlfiR7FE_tkMei8SNNktEAxv0YLausl_gBXxrEvTm54/edit" } },
      { id: 3, type: "mc", lo: "LO1", text: "What is the minimum deal size that triggers an MSA requirement at Amplitude?", options: ["$25,000", "$50,000", "$100,000", "$250,000"], correct: 1, explanation: "The MSA (Master Service Agreement) is required for customers who have purchased a paid subscription of at least $50K. Below this threshold, customers may operate on Amplitude's standard online terms without a negotiated MSA. This threshold matters for deal velocity: smaller deals can close faster without going through MSA negotiation, while deals at or above $50K should anticipate Legal's involvement in contract review.", resource: { label: "CLM Slides — MSA: Governs Customers with Paid Subscription (at least $50K)", url: "https://docs.google.com/presentation/d/1qlfiR7FE_tkMei8SNNktEAxv0YLausl_gBXxrEvTm54/edit" } },
      { id: 4, type: "mc", lo: "LO2", text: "An AE is at S6 Negotiation. The customer's Legal team has sent back redlines on the Order Form. What's the correct process to handle these?", options: ["Reply directly to the customer's Legal team via email with Amplitude's counter-redlines", "Create a Salesforce case to engage Legal — all contract redline questions and reviews go through Legal via the proper SFDC case process, not through direct email threads", "Ask your FLM to review the redlines and approve any changes before sending to Legal", "Handle simple redlines yourself and escalate only complex ones to Legal"], correct: 1, explanation: "All Legal engagement for customer agreements goes through the Salesforce case process. AEs should not negotiate redlines directly with customers via email — this creates version control issues, untracked commitments, and legal liability. Create a SFDC case, tag Legal (Joy Udom's team), and let Legal manage the redline review. For general process questions post in #help-legal. The CLM Confluence page has step-by-step guides for exactly this workflow.", resource: { label: "CLM Slides — Resources: Create a Salesforce Case for Customer Questions", url: "https://docs.google.com/presentation/d/1qlfiR7FE_tkMei8SNNktEAxv0YLausl_gBXxrEvTm54/edit" } },
      { id: 5, type: "mc", lo: "LO3", text: "A prospect is in healthcare and wants to use Amplitude to track patient app engagement data that includes protected health information (PHI). Which additional agreement is required beyond the standard MSA and Order Form?", options: ["A DPA (Data Processing Addendum) — all data processing requires a DPA", "An InfoSec Addendum — security review is required for healthcare customers", "A BAA (Business Associate Addendum) — it permits the customer to process personal health information (PHI) through Amplitude's services and is required for HIPAA compliance", "No additional agreements — the standard MSA covers all data types including PHI"], correct: 2, explanation: "A Business Associate Addendum (BAA) is required for healthcare customers who will process Personal Health Information (PHI) through Amplitude. This is a HIPAA compliance requirement — without a BAA, Amplitude cannot legally be used to process PHI. This should surface early in discovery with healthcare prospects: 'Will you be tracking any data that includes protected health information?' If yes, flag Legal early and factor BAA negotiation into the deal timeline. GA4's lack of HIPAA compliance is actually a competitive advantage for Amplitude in healthcare.", resource: { label: "CLM Slides — BAA: Permits Processing of PHI Through Amplitude Services", url: "https://docs.google.com/presentation/d/1qlfiR7FE_tkMei8SNNktEAxv0YLausl_gBXxrEvTm54/edit" } },
      { id: 6, type: "tf", lo: "LO1", text: "True or False: For DocuSign signature, the standard practice at Amplitude is that Amplitude countersigns the Order Form first, then sends to the customer to sign.", options: ["True", "False"], correct: 1, explanation: "Per the Deal Desk CPQ deck: 'Standard practice is Customer signs first and Amplitude countersigns.' This is standard commercial practice — the customer's signature commits them first, then Amplitude countersigns to execute the agreement. Deviating from this (having Amplitude sign first) creates operational complexity and risk. If a customer requests that Amplitude sign first, that requires a conversation with Legal and Deal Desk.", resource: { label: "Deal Desk + CPQ Slides — DocuSign Order Form Process (Customer Signs First)", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 7, type: "mc", lo: "LO2", text: "Before sending an Order Form to a customer via DocuSign, you notice it doesn't have an Amplitude stamp on it. What should you do?", options: ["Send it anyway — the stamp is administrative and doesn't affect the legal validity of the document", "Add the stamp yourself by downloading the PDF and using a PDF editor", "Stop immediately and reach out to Deal Desk — an unstamped Order Form should never be sent to a customer. Standard OFs have a stamp under the signature block; custom/offline OFs have it in the footer of every page.", "Ask your FLM to review the document and confirm it's acceptable to send"], correct: 2, explanation: "Per the Deal Desk deck: 'If you don't see a stamp on the Order Form you are sending to the customer — STOP — and reach out to Deal Desk.' The Amplitude stamp on an Order Form is the official mark of authorization — it means Deal Desk has reviewed and approved the document. Sending an unstamped OF to a customer creates legal exposure and administrative chaos. Standard OFs: stamp under signature block. Custom/offline OFs: stamp in footer of every page.", resource: { label: "Deal Desk + CPQ Slides — Order Form Stamp (STOP if No Stamp)", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 8, type: "fill", lo: "LO1", text: "For process questions about Legal and contracts, AEs should post in the ________ Slack channel.", correct: ["#help-legal", "help-legal"], placeholder: "Slack channel...", explanation: "#help-legal is the Slack channel for process questions about Legal and contract management. For technical issues in Salesforce, submit a business systems ticket. For step-by-step guides on agreement types and processes, check the Confluence page. Using the right channel gets you to the right expert and creates an audit trail of the question and answer.", resource: { label: "CLM Slides — Resources (#help-legal)", url: "https://docs.google.com/presentation/d/1qlfiR7FE_tkMei8SNNktEAxv0YLausl_gBXxrEvTm54/edit" } },
      { id: 9, type: "mc", lo: "LO2", text: "A customer asks for a Future Purchase Option (FPO) to be shown on their Order Form. What's the correct way to add this in 2026 PPL?", options: ["Create an IronClad ticket with Legal to add a FPO Addendum to the Order Form", "Select the 'OF-Display FPO' checkbox on the Quote page in Salesforce — this is the self-serve way to display FPO on 2026 PPL Order Forms", "Open a Deal Desk case and ask them to add the language to the offline Order Form", "FPOs are no longer available on 2026 PPL Order Forms"], correct: 1, explanation: "For Future Purchase Options (FPO) on 2026 PPL, the correct self-serve path is to select the 'OF-Display FPO' checkbox on the Quote page in Salesforce. This is one of the key takeaways from the Deal Desk MindTickle training. Knowing this self-serve option saves a Deal Desk case and speeds up the deal. If you have questions about the FPO terms or need non-standard FPO language, that's when you create a Deal Desk case.", resource: { label: "Deal Desk + CPQ Slides — Key Takeaways: FPO Display (OF-Display FPO Checkbox)", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 10, type: "mc", lo: "LO3", text: "You're closing a deal and the customer's procurement team says: 'We need to process payment through AWS Marketplace — can Amplitude accommodate that?' What's the correct response and process?", options: ["Decline — Amplitude doesn't support AWS Marketplace purchases", "Yes, it's possible — the process is: open a Deal Desk case with the customer's AWS Account ID, the buyer's name and email (who has AWS Marketplace access), and clarification on whether they're using Amplitude's standard Terms or a custom MSA. Once the customer accepts the Offer via AWS, move the Opportunity to Stage 6.5.", "Yes, but only for deals under $50K — larger deals cannot be processed through AWS Marketplace", "AWS Marketplace purchases bypass the standard order form process — no Deal Desk involvement needed"], correct: 1, explanation: "AWS Marketplace is a supported purchase channel at Amplitude. The process: (1) open a Deal Desk case with the customer's AWS Account ID, buyer name/email, and MSA status, (2) Deal Desk creates the AWS Marketplace offer, (3) customer accepts the offer via AWS, (4) move Opportunity to Stage 6.5. The step-by-step guide is linked in the Deal Desk CPQ deck. AWS Marketplace deals still require proper opportunity hygiene and Deal Desk coordination — they don't bypass the standard process.", resource: { label: "Deal Desk + CPQ Slides — AWS Marketplace Process", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
    ],
  },
  {
    id: "day14", day: "Day 14", title: "Deal Desk & CPQ", week: "Week 4",
    questions: [
      { id: 1, type: "mc", lo: "LO1", text: "What are the three stated missions of the Deal Desk team at Amplitude?", options: ["Quote generation, Order Form management, and Contract archiving", "Strategic & Trusted Advisors (scale commercial best practices), Close Healthy Deals (optimal pricing and structure), and Drive Deal Velocity (process improvement and enablement)", "Pricing approval, Legal coordination, and CRM hygiene", "Revenue forecasting, Deal structuring, and Customer success handoffs"], correct: 1, explanation: "Per the Deal Desk deck, the three missions are: (1) Strategic & Trusted Advisors — coach and advise to scale commercial best practices, identify opportunities for Bigger Better Faster deals; (2) Close Healthy Deals — support optimal pricing and terms, partner cross-functionally, because a healthy land deal = better renewals; (3) Drive Deal Velocity — process improvement and enablement. Understanding Deal Desk as a strategic partner (not just a quoting service) changes how you engage with them — bring them in early on complex deals, not just at the quote stage.", resource: { label: "Deal Desk + CPQ Slides — How Can Deal Desk Help You? (3 Missions)", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 2, type: "mc", lo: "LO1", text: "How do you engage Deal Desk for support on a specific deal?", options: ["Post in the #help-salesops Slack channel and tag @DealDesk", "Email the Deal Desk team distribution list with your request", "From the Opportunity or Quote in Salesforce, click into 'Cases' → 'New' → select 'Deal Desk' as the record type → select 'Deal Desk Support' → fill in Issue Type, Subject, and Description", "Create a Jira ticket and assign it to the Deal Desk team"], correct: 2, explanation: "The correct process to engage Deal Desk is: open a Salesforce case from the Opportunity or Quote → select 'Deal Desk' as record type → select 'Deal Desk Support' → fill in Issue Type, Subject, and Description. All follow-up communications happen via Chatter on that case — keep everything in Chatter so Deal Desk can track context. Slacking individual Deal Desk members or emailing outside SFDC creates fragmentation and delays. The more context you provide in the Description, the faster Deal Desk can act.", resource: { label: "Deal Desk + CPQ Slides — How & When to Engage with Deal Desk (SFDC Case Process)", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 3, type: "mc", lo: "LO2", text: "You're building a quote in CPQ and receive an error: 'Please add the following required implementation SKU to save this quote: Amplitude Essential Platform Implementation.' What does this mean and what do you do?", options: ["It's a system bug — submit a ticket to the business systems team", "The customer has opted out of implementation services — update the quote to remove the implementation requirement", "CPQ is enforcing the mandatory implementation attach requirement for 2026 PPL. Navigate to the 'wrench' icon on the first line item and select the correct implementation SKU based on the deal's ARR tier. You cannot save the quote without it.", "Click 'Ignore' on the warning and proceed — implementation is optional for some deal types"], correct: 2, explanation: "This is the CPQ system enforcing the mandatory implementation mandate for 2026 PPL. To resolve it: navigate to the wrench icon on the first line item (not the 'Add Products' button at the top) and select the correct implementation SKU. The wrench icon keeps all products within the bundle. The 'Add Products' button at the top is only for the One Time Discount SKU. If you believe the deal qualifies for an implementation waiver, that requires Deal Desk + CRO approval — you can't simply dismiss the error.", resource: { label: "Deal Desk + CPQ Slides — Product Configurator: Required Implementation SKU Error", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 4, type: "mc", lo: "LO1", text: "What does FPO stand for, and when is it relevant in a deal?", options: ["Final Purchase Option — used when the customer is ready to sign", "Future Purchase Option — a provision in the Order Form that shows what products and pricing the customer can add during the contract term without requiring new negotiation", "Fixed Price Override — used when the AE needs to hold pricing from a previous quote", "Finance Pre-Approval Option — used when the deal requires executive sign-off before quoting"], correct: 1, explanation: "FPO stands for Future Purchase Option. It appears on the Order Form and shows what products the customer can add later in their contract term at pre-agreed pricing — without requiring a full renegotiation. FPOs are a deal acceleration tool: they allow customers to feel confident in their initial purchase while having a clear path to expand. To add an FPO to a 2026 PPL Order Form, select the 'OF-Display FPO' checkbox on the Quote page. For non-standard FPO terms, open a Deal Desk case.", resource: { label: "Deal Desk + CPQ Slides — Amplitude Acronyms (FPO = Future Purchase Option)", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 5, type: "match", lo: "LO1", text: "Match each CPQ acronym to its full meaning.", pairs: [{ term: "ARR", match: "Annual Recurring Revenue — the annualized value of subscription contracts" }, { term: "TCV", match: "Total Contract Value — the full value of the contract across all years" }, { term: "CPQ", match: "Configure-Price-Quote — the Salesforce quoting system used to build and generate quotes" }, { term: "FPO", match: "Future Purchase Option — pre-agreed pricing for products the customer may add during the contract term" }], correct: 0, explanation: "These are the core commercial acronyms at Amplitude. ARR is the primary revenue metric — it's what you're measured on, what renewals are tracked by, and what forecasting is based on. TCV is useful for multi-year deal comparisons. CPQ is the Salesforce quoting system — everything runs through it. FPOs appear on Order Forms when customers want the ability to expand without renegotiating commercial terms. Knowing these cold prevents embarrassing pauses in deal conversations.", resource: { label: "Deal Desk + CPQ Slides — Amplitude Acronyms Table", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 6, type: "mc", lo: "LO2", text: "You're building an amendment quote for an existing customer who wants to add Session Replay. What's a critical thing to check before saving the quote?", options: ["Verify the customer's billing contact is up to date in Salesforce", "Check whether the contract you're amending already has existing POT add-on SKUs. If yes and you're adding more EV/MTUs, include the existing POT SKUs so they scale with the volume increase. If the SR add-on is new to this contract, just add it as an additional product.", "Make sure the quote expiration date is set to at least 30 days out", "Confirm with your FLM that the discount level is within guidelines before building the amendment"], correct: 1, explanation: "Amendment quoting has a specific nuance with POT SKUs: if the existing contract already has POT add-ons (like Guides & Surveys) and you're adding more EV/MTUs in the amendment, you must include those existing POT SKUs so they reprice correctly with the new volume. If the POT add-on (SR in this case) is brand new to the contract, just add it as an additional product. Getting this wrong means the quote won't correctly price the add-ons at the new volume — a Deal Desk rework and potential deal delay. Also: the Percent Discount field doesn't work on amendments — use Target Net Total instead.", resource: { label: "Deal Desk + CPQ Slides — Amendment Quotes: POT SKUs Key Points to Remember", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 7, type: "tf", lo: "LO1", text: "True or False: Selling above the Guided Selling Price (but below the List Price) requires Deal Desk and executive approval.", options: ["True", "False"], correct: 1, explanation: "The CPQ shows the Guided Selling Price in the Regular Total column — this is the recommended price based on market research and historical transaction data. You can sell higher than Guided (up to List) without special approval. Selling above List requires VP approval (routed through CPQ automatically). Selling above list is generally not recommended: 'Selling above list rates significantly increases the probability of customer churn or a competitor offering a better deal.' The Guided Price is designed to help you win — use it as your default.", resource: { label: "Deal Desk + CPQ Slides — Simplified Pricing: Guided Price vs List Rate", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 8, type: "fill", lo: "LO1", text: "In the 2026 PPL CPQ Quote Line Editor, Implementation and PSP discounts can only be edited at the ________ level.", correct: ["line", "line level", "individual line", "individual line level"], placeholder: "which level...", explanation: "Implementation, Services, and PSP SKUs can only be discounted at the line level in the CPQ QLE — they are NOT included in the Target Net Total calculation that applies to subscription products. This means you can't use Target Net Total to price your implementation SKUs — you must manually set the discount on each PS line item individually. Missing this causes quoting errors and delays. For any non-standard PS quoting (custom SOWs, implementation waivers), open a Deal Desk case.", resource: { label: "Deal Desk + CPQ Slides — Quote Nuances: Implementation/PSP Edited at Line Level Only", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 9, type: "mc", lo: "LO3", text: "An AE submits a quote for approval and it gets flagged: 'Business Case Justification incomplete.' What does a good Business Case include?", options: ["A summary of the customer's pain points and how Amplitude solves them", "The 'gives and gets' of the deal, which approvals are being triggered and why, a commercial summary (CPM/discount/ARR change/payment terms), and an explanation of any changes from the last approval round", "The MEDDPICC qualification notes for the opportunity", "A comparison of this deal's pricing to similar deals in the same industry"], correct: 1, explanation: "Per the Deal Desk deck, a good Business Case includes: (1) Gives/Gets — what is Amplitude conceding and what is the customer committing to in return? (2) Summary of asks — what approvals are being triggered? Touch on each ask individually. (3) Commercial summary — CPM (if EV), discount level, ARR increase/decrease, payment terms. (4) If re-routing through approvals — explain what changed from the last round. A vague Business Case means Deal Desk has to come back for more information — slowing down the approval and potentially the deal close.", resource: { label: "Deal Desk + CPQ Slides — What Does a Good Business Case Look Like?", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 10, type: "mc", lo: "LO2", text: "When should you engage Deal Desk early in a deal — before you're ready to build a quote?", options: ["Never — Deal Desk only needs to be involved at the quoting stage", "Only when the deal is over $500K ARR", "Any time you have a complex deal structure (ramps, multi-year, partner involvement, non-standard terms, custom billing, aggressive discount needs, or a potential waiver request) — Deal Desk is a strategic advisor, not just a quoting team. Early alignment prevents surprises at the approval stage.", "Whenever your FLM asks you to — otherwise handle deal structure on your own"], correct: 2, explanation: "Deal Desk's stated mission includes being Strategic & Trusted Advisors who identify opportunities for Bigger Better Faster deals. Bringing Deal Desk in early on complex structures — ramps, multi-year, partner sub-co situations, aggressive pricing requests — means they can advise on the optimal structure before you've committed to a direction with the customer. Showing up with a half-built complex deal at the approval stage creates delays and structural fixes that slow velocity. The right time to engage Deal Desk on complex deals is at deal strategy, not at deal signing.", resource: { label: "Deal Desk + CPQ Slides — Strategic & Trusted Advisors (Engage Early on Complex Deals)", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
    ],
  },
  {
    id: "day15", day: "Day 15", title: "Leveraging Solution Engineers & Professional Services", week: "Week 4",
    questions: [
      { id: 1, type: "mc", lo: "LO1", text: "At which CEM stages are Solution Engineers (SEs) actively involved in a new business deal?", options: ["S0 through S7 — SEs are involved at every stage of the deal cycle", "S1 and S2 only — SEs run discovery and qualification, then hand off to the AE", "S2 (Qualification), S3 (Business & Technical Evaluation), S4 (Proof of Value), and S5 (Proposal) — SEs are not involved at S0 or S1 unless consulted on technical criteria", "S4 only — SEs are exclusively POC resources"], correct: 2, explanation: "Per the SE Partnership slides, SEs are actively involved at S2 (Qualify/Justify), S3 (Business & Technical Evaluation), S4 (Proof of Value/POC), and S5 (Proposal — consulted if technical value is still in play). At S0 and S1, the SE is consulted only if technical criteria emerge. Understanding this prevents two common mistakes: bringing in the SE too early (before there's a qualified opportunity) or too late (after the technical win window has closed).", resource: { label: "Leveraging SEs Deck — Where Are SEs Involved? (S2, S3, S4, S5)", url: "https://docs.google.com/presentation/d/1kDmK2l_Ahv01UlrBDSWoPqhtT70dQTcBT2GJ6PoSZzA/edit" } },
      { id: 2, type: "mc", lo: "LO1", text: "You need SE support on an active qualified opportunity. What are the two ways to engage an SE?", options: ["Email the SE directly or create a Zendesk ticket", "Informal — DM the SE, post in #salesengineering, or ask for advice on early-stage calls and account prioritization. Formal — file a formal SC request in Salesforce; SE triage happens within 24 hours if the required information is included.", "Only through your FLM — AEs should not contact SEs directly without manager approval", "Post in #help-salesops for triage, then the SE manager assigns the right SE to the deal"], correct: 1, explanation: "Two engagement paths: Informal — DM, #salesengineering, or ask for lightweight help on discovery prep, account prioritization, or early qualification questions. Formal — file a formal SC request in Salesforce for active opportunities requiring SE involvement. The formal request is triaged within 24 hours if you include the required information. Pro tip: set up a prep session at least one day before any customer meeting involving the SE — share notes in advance, come ready to discuss deal state, gaps, ideal outcomes, and roles & responsibilities.", resource: { label: "Leveraging SEs Deck — How to Request an SE (Informal vs Formal SC Request)", url: "https://docs.google.com/presentation/d/1kDmK2l_Ahv01UlrBDSWoPqhtT70dQTcBT2GJ6PoSZzA/edit" } },
      { id: 3, type: "mc", lo: "LO2", text: "A prospect says 'We want a POC' at the S2 stage. Before committing the SE's time, what's the right first question to ask?", options: ["What's your timeline for the evaluation?", "What does a POC mean to you? — The term 'POC' covers a wide spectrum: from a 30-minute custom demo (low time investment, no Evaluation Plan needed) to a full End User Access POC with real data (high time investment, Evaluation Plan required). Clarifying what they're actually asking for determines the right evaluation type and whether an Evaluation Plan is required.", "How many users will participate in the POC?", "Do you have technical resources available to support the implementation?"], correct: 1, explanation: "Per the SE Partnership deck, 'POC' is ambiguous and overloaded. The evaluation types range widely: Custom Demo (low effort, no plan needed), Hands-On Workshop (low effort), Demo Account Access (low effort), Technical Validation (medium, requires Evaluation Plan), Session Replay POC (medium, requires plan), End User Access POC (high, requires plan, only for opps >$75K), and Experiment POC (high, requires plan). Jumping to a high-effort POC when a custom demo would win the deal wastes SE time and creates unnecessary risk. Clarify before committing.", resource: { label: "Leveraging SEs Deck — POC Qualification: Types of Evaluation", url: "https://docs.google.com/presentation/d/1kDmK2l_Ahv01UlrBDSWoPqhtT70dQTcBT2GJ6PoSZzA/edit" } },
      { id: 4, type: "match", lo: "LO1", text: "Match each evaluation type to its time investment and whether an Evaluation Plan is required.", pairs: [{ term: "Custom Demo", match: "Low time investment — SE builds a tailored demo based on customer use cases. No Evaluation Plan required." }, { term: "Technical Validation", match: "Medium time investment — customer validates their data structure, SDKs, and integrations. Evaluation Plan required." }, { term: "End User Access POC", match: "High time investment — customer's end users access real data in Amplitude. Evaluation Plan required. Only for opps >$75K." }, { term: "Experiment POC", match: "High time investment — technically validates A/B test implementation. Evaluation Plan required." }], correct: 0, explanation: "Evaluation type selection is a deal strategy decision, not a default response to every 'we want a POC' request. Custom Demos and Hands-On Workshops are the most efficient path to technical validation for most deals. High-effort evaluations (End User Access POC, Experiment POC) should only be run when the deal size and qualification level justify the investment — and they always require an Evaluation Plan with agreed success criteria. Without a plan, a POC drifts and rarely produces a clear win.", resource: { label: "Leveraging SEs Deck — Types of Evaluation Table (Time Investment & Evaluation Plan)", url: "https://docs.google.com/presentation/d/1kDmK2l_Ahv01UlrBDSWoPqhtT70dQTcBT2GJ6PoSZzA/edit" } },
      { id: 5, type: "mc", lo: "LO2", text: "An AE schedules an SE for a customer meeting but doesn't share any context until 10 minutes before the call. What's wrong with this approach and what should happen instead?", options: ["Nothing — SEs are experienced enough to handle any meeting without preparation", "The AE should have sent notes at least one day before the call and scheduled a 15–30 minute prep session. An effective AE-SE prep covers: transfer of information (notes and account plan), identifying the goal and outcome of the meeting, spotting gaps in deal information, defining roles and responsibilities, and finalizing the meeting plan. Walking into a meeting without alignment wastes the SE's expertise and risks an unfocused customer interaction.", "The AE should send the notes via Slack immediately before the call — as long as the SE reviews them before starting, the prep is sufficient", "The SE should reschedule the meeting if they haven't received adequate preparation materials"], correct: 1, explanation: "Effective AE-SE partnership requires preparation — not improvisation. The SE Partnership deck specifies: 15–30 minute prep session at least one day before the customer meeting. The prep covers: brief review of prior call notes and account plan, identifying the goal and outcome, spotting information gaps, agreeing on which gaps to fill in the next touchpoint, identifying additional discovery and trap-setting questions, defining roles & responsibilities, and finalizing the meeting plan. A well-prepped SE operates as a co-pilot, not a presenter-for-hire.", resource: { label: "Leveraging SEs Deck — Ideal Prep Session (15–30 Mins, at Least 1 Day Before)", url: "https://docs.google.com/presentation/d/1kDmK2l_Ahv01UlrBDSWoPqhtT70dQTcBT2GJ6PoSZzA/edit" } },
      { id: 6, type: "tf", lo: "LO1", text: "True or False: An End User Access POC — where the customer's end users access their real data in Amplitude — is available for all qualified opportunities regardless of deal size.", options: ["True", "False"], correct: 1, explanation: "End User Access POCs require significant SE time and internal resources — they're reserved for opportunities over $75K. Below that threshold, customers can access the demo environment at analytics.amplitude.com. This threshold exists to protect SE capacity and ensure high-effort evaluations are attached to deals that can justify the investment. If a <$75K opportunity is requesting an End User Access POC, have the strategic conversation about deal size first.", resource: { label: "Leveraging SEs Deck — POC Qualification: End User Access POC (Opps >$75K Only)", url: "https://docs.google.com/presentation/d/1kDmK2l_Ahv01UlrBDSWoPqhtT70dQTcBT2GJ6PoSZzA/edit" } },
      { id: 7, type: "mc", lo: "LO3", text: "You're at S3 Business & Technical Evaluation. Your SE is leading the technical discovery and custom demo. What is the AE's primary role during this stage?", options: ["Let the SE run the calls — the AE's job is to stay silent and not interrupt the technical conversation", "Build and align on the Evaluation Plan, lead Champion coaching sessions, drive Business Value Assessment and success story delivery, update the MAP, manage EB engagement and stakeholder alignment, and coordinate with the SE on the technical scope — not disappear", "Focus entirely on pricing negotiations while the SE handles the technical side", "Create the SFDC opportunity and update mandatory S3 fields — administrative work is the AE's S3 responsibility"], correct: 1, explanation: "Per the CEM S3 AE responsibilities: build and align on Evaluation Plan with SE, lead Champion coaching sessions, drive BVA and success story delivery, update MAP with shared evaluation dates, manage EB engagement and stakeholder alignment, internal check-in with FLM, update SFDC mandatory S3 fields, and align with partner if co-sell. The SE is accountable for the Technical Win Path — custom demo, technical use case deep-dive, evaluation plan design. Both must be running in parallel. An AE who disappears during S3 and lets the SE 'run the deal' loses control of the commercial thread.", resource: { label: "Customer Engagement Model — S3 Business & Technical Evaluation: AE Responsibilities", url: "https://docs.google.com/document/d/1VxMWNbIWWEtJwuhNibKHUCsbOsCQqVFcin8vrZkeKZw/edit" } },
      { id: 8, type: "fill", lo: "LO1", text: "The Slack channel where you can find and connect with the Solutions Engineering team is ________.", correct: ["#salesengineering", "#solutions-engineering", "salesengineering", "solutions-engineering"], placeholder: "channel name...", explanation: "The SE team's Slack channel is #salesengineering (also referenced as #solutions-engineering). Use it for informal questions, early-stage discovery prep, competitive intel, or to flag an account you want SE perspective on before filing a formal request. The SE team is a shared resource — the informal channel is for lightweight questions, while formal SFDC requests are for active opportunities requiring dedicated SE engagement.", resource: { label: "Leveraging SEs Deck — Where to Find Us (#salesengineering)", url: "https://docs.google.com/presentation/d/1kDmK2l_Ahv01UlrBDSWoPqhtT70dQTcBT2GJ6PoSZzA/edit" } },
      { id: 9, type: "mc", lo: "LO3", text: "A prospect at S3 says: 'We're a Mixpanel customer today — before we go further, we need to see a head-to-head comparison with your product.' How should the AE and SE approach this?", options: ["Decline the head-to-head — competitive bake-offs rarely go well and should be avoided", "Agree immediately and schedule a bake-off demo for the following week — showing confidence wins deals", "Use this as a Trap-Setting opportunity. Before building the bake-off, work with the SE to agree on the evaluation criteria first — and shape those criteria around Amplitude's differentiators (cross-functional self-service, breadth of analysis, integrated experimentation). If Mixpanel's criteria are 'SQL-based analytics,' you'll lose. If the criteria are 'non-technical self-service and integrated workflows,' you'll win. Control the frame before committing to the evaluation.", "Redirect to a POC instead — a live POC with their data is more compelling than a feature comparison"], correct: 2, explanation: "Competitive evaluations are won or lost before they start — in how the evaluation criteria are defined. The AE-SE prep session for a Mixpanel bake-off should identify: what criteria does the prospect currently have? Are those criteria shaped around Mixpanel's strengths? Use Trap-Setting questions to surface Amplitude's differentiators as requirements: 'How important is it that your marketing and growth teams can self-serve analytics without going through an analyst?' That's a capability Mixpanel struggles with and Amplitude excels at. Win the criteria; win the bake-off.", resource: { label: "Leveraging SEs Deck — How to Have an Effective Partnership (Trap-Setting Questions)", url: "https://docs.google.com/presentation/d/1kDmK2l_Ahv01UlrBDSWoPqhtT70dQTcBT2GJ6PoSZzA/edit" } },
      { id: 10, type: "mc", lo: "LO2", text: "After a successful S4 POC, the SE documents the Technical Win. What specifically must happen at S4 exit, and who owns each item?", options: ["The SE sends a POC summary email to the customer — that constitutes the Technical Win documentation", "Technical Win confirmed by Champion and technical stakeholders and documented in SFDC (SE-owned), Path to Production completed with Architecture Diagram (SE), Services attached and forecasted (AE), Champion ready to support internal business case (AE), Deployment plan drafted (TSM), Security/Legal reviews initiated (AE), and SFDC updated (AE/SE shared)", "The AE submits the proposal — the Technical Win documentation happens automatically when the deal moves to S5", "The customer signs an evaluation completion form — that's the formal Technical Win confirmation"], correct: 1, explanation: "S4 exit requires multiple owners completing specific items: (1) Technical Win confirmed by Champion/technical stakeholders and documented — SE owns this. (2) Path to Production with Architecture Diagram documented — SE. (3) Services attached and forecasted — AE. (4) Champion ready to support internal business case — AE. (5) Deployment plan drafted (TSM leads for deals >$100K). (6) Security/Legal reviews initiated — AE. (7) SFDC updated — shared. Missing any of these means you're not actually at S4 exit — you're at risk of a deal that slips because the internal business case hasn't been built or security review creates a last-minute surprise.", resource: { label: "Customer Engagement Model — S4 Proof of Value Exit Criteria", url: "https://docs.google.com/document/d/1VxMWNbIWWEtJwuhNibKHUCsbOsCQqVFcin8vrZkeKZw/edit" } },
    ],
  },
];
